import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';

@Component({
  selector: 'app-accounts',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './accounts.component.html',
  styleUrl: './accounts.component.css',
})
export class AccountsComponent {
  filter = signal('');

  customers = computed(() =>
    this.seed.accounts().filter((a) => a.type !== 'manufacturer' && a.type !== 'distributor'),
  );

  partners = computed(() =>
    this.seed.accounts().filter((a) => a.type === 'manufacturer' || a.type === 'distributor'),
  );

  filteredCustomers = computed(() => {
    const q = this.filter().trim().toLowerCase();
    if (!q) return this.customers();
    return this.customers().filter((a) => a.name.toLowerCase().includes(q));
  });

  totalAccounts = computed(() => this.customers().length);
  totalBacklog = computed(() =>
    this.customers().reduce((sum, a) => sum + a.backlogValue, 0),
  );
  atRiskCount = computed(() =>
    this.customers().filter((a) => a.connectionLevel === 'at-risk').length,
  );

  healthBadge(level: string): string {
    switch (level) {
      case 'strong': return 'badge-success';
      case 'developing': return 'badge-warning';
      case 'at-risk': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  onFilter(value: string): void {
    this.filter.set(value);
  }

  constructor(public seed: SeedService) {}
}
